import { z } from "zod"

/**
 * Schema for initiating a simulated course checkout.
 *
 * Only `courseId` is needed from the client. User identity comes from the
 * authenticated session; price is looked up server-side from `course_prices`.
 * No real card data is collected - this is a simulation-only flow.
 */
export const checkoutSchema = z.object({
  courseId: z.string().uuid("Course ID must be a valid UUID"),
})

/**
 * Schema for confirming a simulated payment event.
 *
 * `simulationEventId` is an opaque idempotency key generated by the simulation
 * layer. It prevents the same simulated event from being processed twice.
 * `fakeSummary` is optional human-readable text for display in the UI or logs.
 */
export const confirmPaymentSchema = z.object({
  courseId: z.string().uuid("Course ID must be a valid UUID"),
  simulationEventId: z
    .string()
    .min(1, "Simulation event ID is required"),
  fakeSummary: z.string().optional(),
})

// ---------------------------------------------------------------------------
// Inferred types
// ---------------------------------------------------------------------------

/** Input type inferred from {@link checkoutSchema}. */
export type CheckoutInput = z.infer<typeof checkoutSchema>

/** Input type inferred from {@link confirmPaymentSchema}. */
export type ConfirmPaymentInput = z.infer<typeof confirmPaymentSchema>
